head.script:
 // 전역 변수
scwin.memJson = $c.data.getMemInfo(); // 로그인 정보를 가져온다.
scwin.lobranCd = scwin.memJson.lobranCd;
if (!$c.gus.cfIsNull(scwin.lobranCd)) {
    scwin.lobranCd = scwin.lobranCd.substring(0, 2) + "2";
} else {
    scwin.lobranCd = "";
}

scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";

scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDateOfMonth(scwin.vCurDate.substring(0, 6));

scwin.pchsSelAmt = 0;
scwin.pchsSelCount = 0;
scwin.pchsDcScSelAmt = 0;
scwin.pchsSelVatAmt = 0;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	const codeOptions = [
        //{ grpCd: "FS261", compID: "acb_copCoConfirmClsCd" }, // 업체확인구분
        { grpCd: "FS262", compID: "acb_pchsAdmitClsCd" }, // 매입승인구분
        { grpCd: "SD113", compID: "acb_odrKndCd" } // 오더종류
    ];
    $c.data.setCommonCode(codeOptions);
};

/**
 * UDC값
 */
scwin.onUdcCompleted = function() {
    acb_dtCls.setSelectedIndex(1);
    scwin.f_SelWrkDt();
    scwin.f_SetDefaultData();
    $c.gus.cfDisableAllBtn();
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function() {
    scwin.f_GetPchsAdmitCntTotAmt(); // 건수/총금액 계산

    ed_copCoConfirmDtSt.setValue(scwin.vQryStDt); // 업체확인일자시작
    ed_copCoConfirmDtEnd.setValue(scwin.vQryEndDt); // 업체확인일자종료
    ed_wrkDtSt.setValue(scwin.vQryStDt); // 실적일자시작
    ed_wrkDtEnd.setValue(scwin.vQryEndDt); // 실적일자종료
    ed_pchsIntendDt.setValue(scwin.vQryEndDt); // 매입예정일자
    $c.gus.cfDisableObjects([ed_pchsIntendDt, ed_pchsIntendDt, ed_rmk, ed_certiNo, btn_certiNo, hid_rmk, ed_pstpnRsn]);

    // cfDisableObjects -> WebSquare setDisabled
    ed_pchsIntendDt.setDisabled(true);
    ed_rmk.setDisabled(true);
    ed_certiNo.setDisabled(true);
    btn_certiNo.setDisabled(true);
    hid_rmk.setDisabled(true);
    ed_pstpnRsn.setDisabled(true);

    //acb_copCoConfirmClsCd.setSelectedIndex(0);
    acb_pchsAdmitClsCd.setSelectedIndex(0);
    acb_odrKndCd.setSelectedIndex(0);

    ed_pchsDeptCd.setValue(scwin.lobranCd);
    ed_pchsDeptNm.setValue("");
    ed_pchsDeptCd.focus();
};

//-------------------------------------------------------------------------
// 벌크하불승인 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveContainerTpchsList = async function() {
    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    if (acb_dtCls.getValue() == "01") { // 업체확인일자 기준
        let ret = await $c.gus.cfValidate([ed_pchsDeptCd, ed_pchsClntNo, ed_copCoConfirmDtSt, ed_copCoConfirmDtEnd]);
        if (!ret) {
            return false;
        }

        if (!await $c.gus.cfIsAfterDate(ed_copCoConfirmDtSt.getValue(), ed_copCoConfirmDtEnd.getValue())) {
            await $c.win.alert("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ed_copCoConfirmDtSt.focus();
            return;
        }
    } else if (acb_dtCls.getValue() == "02" || acb_dtCls.getValue() == "03") { // 실적일자/운송일자 기준
        let ret = await $c.gus.cfValidate([ed_pchsDeptCd, ed_pchsClntNo, ed_wrkDtSt, ed_wrkDtEnd]);
        if (!ret) {
            return false;
        }

        if (!await $c.gus.cfIsAfterDate(ed_wrkDtSt.getValue(), ed_wrkDtEnd.getValue())) {
            await $c.win.alert("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ed_wrkDtSt.focus();
            return;
        }
    }

    // 구분(미확인포함여부/미승인포함여부)- 쿼리문에서 사용
    if (cbx_unAdmitIncluYn.getValue() == 0) {
        dma_searchContainerTpchsAdmissionList.set("incluYn", "N");
    } else {
        dma_searchContainerTpchsAdmissionList.set("incluYn", "Y");
    }

    dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
    dma_searchContainerTpchsAdmissionList.set("pchsClntNo", ed_pchsClntNo.getValue());
    dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
    dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
    dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
    dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());

    $c.sbm.execute(sbm_searchContainerTpchsAdmissionList);
};

//-------------------------------------------------------------------------
// 신규매입승인 등록
//-------------------------------------------------------------------------
scwin.f_NewPurchaseAdmission = async function() {
    // Data 변경 여부 조회
    if (ds_containerTpchsAdmissionList.getModifiedIndex().length == 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, ["자료"]));
        return;
    }

    // 매입승인구분(FS262)이 02:승인이 아닌 경우
    let copCoConfirmClsCd = "";
    let pchsAdmitClsCd = "";
    let consignYn = "";
    let mbssysVehclYn = "";

    let checkedRows = gr_containerTpchsAdmissionList.getCheckedIndex("chk");

    for (let i = 0; i < checkedRows.length; i++) {
        let row = checkedRows[i];
        copCoConfirmClsCd = ds_containerTpchsAdmissionList.getCellData(row, "copCoConfirmClsCd");
        pchsAdmitClsCd = ds_containerTpchsAdmissionList.getCellData(row, "pchsAdmitClsCd");
        consignYn = ds_containerTpchsAdmissionList.getCellData(row, "consignYn");
        mbssysVehclYn = ds_containerTpchsAdmissionList.getCellData(row, "mbssysVehclYn");

        if (copCoConfirmClsCd != "02" && consignYn == "N" && mbssysVehclYn == 0) {
            await $c.win.alert("업체확인이 확인인 경우만 가능합니다.");
            return;
        }

        if (pchsAdmitClsCd == "02") {
            await $c.win.alert("매입승인이 미승인, 보류인 경우만 가능합니다.");
            return;
        }
    }

    // 세금계산서작성일자 체크
    let ret = await $c.gus.cfValidate([ed_pchsIntendDt]);
    if (!ret) {
        return false;
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
        dma_purchaseCerti.set("selpchItemCd", "0131"); // 매출입항목코드(하불임)
        dma_purchaseCerti.set("pchsGoodsPatternCd", "01"); // 매입품목유형코드(컨테이너)

        $c.sbm.execute(sbm_saveContainerTpchsAdmissionList);
    }
};

//-------------------------------------------------------------------------
// 추가매입승인 등록
//-------------------------------------------------------------------------
scwin.f_AdditionPurchaseAdmission = async function() {
    // Data 변경 여부 조회
    if (ds_containerTpchsAdmissionList.getModifiedIndex().length == 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, ["자료"]));
        return;
    }

    // 매입승인구분(FS262)이 02:승인이 아닌 경우
    let copCoConfirmClsCd = "";
    let pchsAdmitClsCd = "";
    let consignYn = "";
    let mbssysVehclYn = "";
    let checkedRows = gr_containerTpchsAdmissionList.getCheckedIndex("chk");

    for (let i = 0; i < checkedRows.length; i++) {
        let row = checkedRows[i];
        copCoConfirmClsCd = ds_containerTpchsAdmissionList.getCellData(row, "copCoConfirmClsCd");
        pchsAdmitClsCd = ds_containerTpchsAdmissionList.getCellData(row, "pchsAdmitClsCd");
        consignYn = ds_containerTpchsAdmissionList.getCellData(row, "consignYn");
        mbssysVehclYn = ds_containerTpchsAdmissionList.getCellData(row, "mbssysVehclYn");

        if (copCoConfirmClsCd != "02" && consignYn == "N" && mbssysVehclYn == 0) {
            await $c.win.alert("업체확인이 확인인 경우만 가능합니다.");
            return;
        }

        if (pchsAdmitClsCd == "02") {
            await $c.win.alert("매입승인이 미승인, 보류인 경우만 가능합니다.");
            return;
        }
    }

    // 거래명세서번호 체크
    let ret = await $c.gus.cfValidate([ed_certiNo]);
    if (!ret) {
        return false;
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
        dma_purchaseCerti.set("selpchItemCd", "0131"); // 매출입항목코드(하불임)
        dma_purchaseCerti.set("pchsGoodsPatternCd", "01"); // 매입품목유형코드(컨테이너)

        $c.sbm.execute(sbm_saveContainerTpchsAdmissionList2);
    }
};

//-------------------------------------------------------------------------
// 매입승인취소 등록
//-------------------------------------------------------------------------
scwin.f_PurchaseAdmissionCancel = async function() {
    // Data 변경 여부 조회
    if (ds_containerTpchsAdmissionList.getModifiedIndex().length == 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, ["자료"]));
        return;
    }

    // 매입승인구분(FS262)이 02:승인인 경우와 매입확정 이전인 경우
    let pchsAdmitClsCd = "";
    let pchsEvidYn = "";
    let checkedRows = gr_containerTpchsAdmissionList.getCheckedIndex("chk");

    for (let i = 0; i < checkedRows.length; i++) {
        let row = checkedRows[i];
        pchsAdmitClsCd = ds_containerTpchsAdmissionList.getCellData(row, "pchsAdmitClsCd");
        pchsEvidYn = ds_containerTpchsAdmissionList.getCellData(row, "pchsEvidYn");

        if (pchsAdmitClsCd != "02") {
            await $c.win.alert("매입승인이 승인인 경우만 가능합니다.");
            return;
        }
        if (pchsEvidYn == "Y") {
            await $c.win.alert("매입확정 이전인 경우만 가능합니다.");
            return;
        }
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
        $c.sbm.execute(sbm_saveContainerTpchsAdmissionList3);
    }
};

//-------------------------------------------------------------------------
// 매입승인보류 등록
//-------------------------------------------------------------------------
scwin.f_PurchasePostpone = async function() {
    // Data 변경 여부 조회
    if (ds_containerTpchsAdmissionList.getModifiedIndex().length == 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, ["자료"]));
        return;
    }

    // 매입승인구분(FS262)이 01:미승인인 경우
    let pchsAdmitClsCd = "";
    let checkedRows = gr_containerTpchsAdmissionList.getCheckedIndex("chk");

    for (let i = 0; i < checkedRows.length; i++) {
        let row = checkedRows[i];
        pchsAdmitClsCd = ds_containerTpchsAdmissionList.getCellData(row, "pchsAdmitClsCd");

        if (pchsAdmitClsCd != "01") {
            await $c.win.alert("매입승인이 미승인인 경우만 가능합니다.");
            return;
        }
    }

    // 보류사유 체크
    let ret = await $c.gus.cfValidate([ed_pstpnRsn]);
    if (!ret) {
        return false;
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
        $c.sbm.execute(sbm_saveContainerTpchsAdmissionList4);
    }
};

//-------------------------------------------------------------------------
// 거래명세서번호 검색
//-------------------------------------------------------------------------
scwin.f_OpenCertiNoPopUp = async function() {
    let rtnList  = new Array();
    if (ds_containerTpchsAdmissionList.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    let ret = await $c.gus.cfValidate([ed_pchsDeptCd, ed_pchsClntNo]);
    if (!ret) {
        return false;
    }

    let args = {};
    args.pchsDeptCd = ed_pchsDeptCd.getValue(); // 매입부서
    args.pchsClntNo = ed_pchsClntNo.getValue(); // 매입거래처
    args.selpchItemCd = "0131"; // 매출입항목코드(하불임)
    args.pchsGoodsPatternCd = "01"; // 매입품목유형코드(컨테이너)

    let wrkDtArr = ds_containerTpchsAdmissionList.getColData("wrkDt");
    wrkDtArr.sort();
    let minDate = wrkDtArr[0];
    let maxDate = wrkDtArr[wrkDtArr.length-1];

    args.pchsIntendDtSt = minDate.substring(0,6)+"01";
    args.pchsIntendDtEnd = maxDate.substring(0,6) + $c.date.getLastDateOfMonth(maxDate.substring(0,6));

    const options = {
        id: "fs_102_01_16p",
        popupName: "거래명세서번호 검색",
        width: 500,
        height: 550,
    };

    rtnList = await $c.win.openPopup("/ui/ds/fs/adjm/fs_102_01_16p.xml", options, args);

    if( rtnList != null){
        ed_certiNo.setValue(rtnList.certiNo);
        hid_rmk.setValue(rtnList.rmk);
    }
};

//-------------------------------------------------------------------------
// 조회건수/조회총금액, 매입승인건수/매입승인총금액 계산
//-------------------------------------------------------------------------
scwin.f_GetPchsAdmitCntTotAmt = function() {
    // 기본하불 + 할증금액
    let qryCnt = 0;
    let qryTotAmt = 0;
    let qryVatAmt = 0;

    if (ds_containerTpchsAdmissionList.getRowCount() > 0) {
        qryCnt = ds_containerTpchsAdmissionList.getRowCount();

        for (let i = 0; i < ds_containerTpchsAdmissionList.getRowCount(); i++) {
            qryTotAmt = qryTotAmt + (Number(ds_containerTpchsAdmissionList.getCellData(i, "basisTpchs")) + Number(ds_containerTpchsAdmissionList.getCellData(i, "dcScAmt")));
            qryVatAmt = qryVatAmt + Number(ds_containerTpchsAdmissionList.getCellData(i, "vat"));
        }
    }

    lay_qryCnt.setValue($c.gus.cfInsertComma(qryCnt + ""));
    lay_qryTotAmt.setValue($c.gus.cfInsertComma(qryTotAmt + ""));
    lay_qryVatAmt.setValue($c.gus.cfInsertComma(qryVatAmt + ""));


    // 매입승인구분이 승인(02)인 경우만 기본하불 + 할증금액 계산
    let pchsAdmitCnt = 0;
    let pchsAdmitTotAmt = 0;
    for (let i = 0; i < ds_containerTpchsAdmissionList.getRowCount(); i++) {
        if (ds_containerTpchsAdmissionList.getCellData(i, "pchsAdmitClsCd") == "02") {
            pchsAdmitTotAmt += Number(ds_containerTpchsAdmissionList.getCellData(i, "basisTpchs")) + Number(ds_containerTpchsAdmissionList.getCellData(i, "dcScAmt"));
            pchsAdmitCnt++;
        }
    }

    lay_pchsAdmitCnt.setValue($c.gus.cfInsertComma(pchsAdmitCnt + ""));
    lay_pchsAdmitTotAmt.setValue($c.gus.cfInsertComma(pchsAdmitTotAmt + ""));
};

//-------------------------------------------------------------------------
// 업체확인일자 선택
//-------------------------------------------------------------------------
scwin.f_SelCopCoConfirmDt = function() {
    udc_copCoConfirm.show();
    //acb_copCoConfirmClsCd.setStyle("display", "none");
    // acb_pchsAdmitClsCd.setStyle("position", "relative"); // 매입승인구분 위치 가변
    // acb_pchsAdmitClsCd.setStyle("left", "0px"); // 매입승인구분 left 위치 지정
    acb_pchsAdmitClsCd.setStyle("display", "block");
    udc_wrkDt.hide();
    //cbx_unconfirmedIncluYn.setStyle("display", "none");
    // cbx_unAdmitIncluYn.setStyle("position", "relative"); // 일자범위이전 매입미승인 포함 위치 가변
    // cbx_unAdmitIncluYn.setStyle("left", "0px"); // 일자범위이전 매입미승인 포함 left 위치 지정
    cbx_unAdmitIncluYn.setStyle("display", "block");
};

//-------------------------------------------------------------------------
// 실적일자/운송일자 선택
//-------------------------------------------------------------------------
scwin.f_SelWrkDt = function() {
    udc_copCoConfirm.hide();
    //acb_copCoConfirmClsCd.setStyle("display", "block");
    // acb_pchsAdmitClsCd.setStyle("position", "relative"); // 매입승인구분 위치 가변
    // acb_pchsAdmitClsCd.setStyle("left", "220px"); // 매입승인구분 left 위치 지정
    acb_pchsAdmitClsCd.setStyle("display", "block");
    udc_wrkDt.show();
    //cbx_unconfirmedIncluYn.setStyle("display", "block");
    // cbx_unAdmitIncluYn.setStyle("position", "relative"); // 일자범위이전 매입미승인 포함 위치 가변
    // cbx_unAdmitIncluYn.setStyle("left", "220px"); // 일자범위이전 매입미승인 포함 left 위치 지정
    cbx_unAdmitIncluYn.setStyle("display", "block");
};

//-------------------------------------------------------------------------
// GRID에서 선택된 cntrNo 세부정보 확인 : 해당 cntrNo 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_CntrNoDetail = function(cntrNo) {
  		let pgmId = "as_102_01_02b.jsp";
  		let url = "/ui/ds/as/cstmrsrvc/coafmgnt/as_102_01_02b.xml";

        let condition = {
            cntrNo : cntrNo
        };

        $c.win.openMenu("컨테이너 화물추적", url, pgmId, condition);
};

//-------------------------------------------------------------------------
// 엑셀 다운로드
//-------------------------------------------------------------------------
scwin.f_RunExcel = async function() {
    let gridColCount = gr_containerTpchsAdmissionList.getTotalCol();
    let count = ds_containerTpchsAdmissionList.getRowCount();
    if (!(count > 0)) {
        await $c.win.alert(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
        return;
    } else {
        let infoArr = [{
            rowIndex : 0,             // 첫 번째 줄
            colIndex : 0,             // 첫 번째 칸부터
            colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
            rowSpan : 1,
            text : "컨테이너 하불 매입 승인",
            textAlign : "center",     //정렬
            fontSize : 12,
            drawBorder : false,        // 테두리
            color : "black",          // 글자색
            backgroundColor : "white" // 배경색
        }]

        const options = {
            fileName: "컨테이너 하불 매입 승인.xlsx",
            sheetName: "컨테이너 하불 매입 승인",
            startRowIndex:2,
            startColumnIndex : 0,
            columnMove:true,
            type : 1
        };
        await $c.data.downloadGridViewExcel(gr_containerTpchsAdmissionList, options, infoArr);
    }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    let rtnList; // 공통POP-UP -> 요청화면

    switch (disGubun) {
        case 1:
            // 점소 팝업
            await udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 2:
            // 협력회사 팝업
            await udc_pchsClnt.cfCommonPopUp(scwin.udc_pchsClnt_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 3:
            // 차량번호 팝업
            await udc_vehclShort.cfCommonPopUp(scwin.udc_vehclShort_callBackFunc, pCode.trim(), pName, pClose, '2', null, null, '3,4,5,6,7,8,9,10', null, null, null, null, null, null, pAllSearch, null);
            break;

        case 4:
            // 화주 팝업
            await udc_realMchtClnt.cfCommonPopUp(scwin.udc_realMchtClnt_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 5:
            // 출발지 팝업
            await udc_dptWrkPl.cfCommonPopUp(scwin.udc_dptWrkPl_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 6:
            // 도착지 팝업
            await udc_arvWrkPl.cfCommonPopUp(scwin.udc_arvWrkPl_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 7:
            // 승인담당자 팝업
            await udc_admitPic.cfCommonPopUp(scwin.udc_admitPic_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 8:
            // 담당자
            await udc_mod.cfCommonPopUp(scwin.udc_mod_callBackFunc, // XML상의 SELECT ID    
                ed_modId.getValue().trim(),
                ed_modNm.getValue(), // 화면에서의 ??? Name Element의    Value
                pClose // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                , null // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서    
                , null // 보여주는 각 컬럼들의 폭  
                , null // 컬럼중에서 숨기는    컬럼 지정   
                , null // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의    사용자 정의 폭
                , null // POP-UP뛰을때 우도우의    사용자 정의 높이    
                , null // 윈도우 위치 Y좌표    
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "등록자,사용자ID,사용자명" // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        default:
            break;
    }
};

