scwin.f_viewSelAmount = function() {
    // 선택한 금액  표시
    ed_select.show();
    ed_select.setValue("선택 건수 : ");
    ed_selectCount.setValue($c.gus.cfInsertComma(scwin.pchsSelCount));
    ed_amount.show();
    ed_amount.setValue("선택 하불금액 : ");
    ed_selectAmount.setValue($c.gus.cfInsertComma(scwin.pchsSelAmt));
    ed_DcScAmount.show();
    ed_DcScAmount.setValue("선택 할증금액 : ");
    ed_selectDcScAmount.setValue($c.gus.cfInsertComma(scwin.pchsDcScSelAmt));
    ed_allAmount.show();
    ed_allAmount.setValue("하불+ 할증 : ");
    ed_selectAllAmount.setValue($c.gus.cfInsertComma(scwin.pchsSelAmt + scwin.pchsDcScSelAmt));
    ed_vatAmount.show();
    ed_vatAmount.setValue("부가세 : ");
    ed_selectVatAmount.setValue($c.gus.cfInsertComma(scwin.pchsSelVatAmt));
};

scwin.sbm_searchContainerTpchsAdmissionList_submitdone = async function (e) {
    let rowCnt = ds_containerTpchsAdmissionList.getRowCount();
    gr_containerTpchsAdmissionList.setFocusedCell(0, 2);
    // 총 조회건수 표시
    totalRows.setValue(rowCnt);

    // 건수/총금액 계산
    scwin.f_GetPchsAdmitCntTotAmt();

    // 매입예정일자
    let inputDate = "";

    if (acb_dtCls.getValue() == "01") { // 업체확인일자 기준
        inputDate = ed_copCoConfirmDtEnd.getValue();
    } else if (acb_dtCls.getValue() == "02" || acb_dtCls.getValue() == "03") { // 실적일자/운송일자 기준
        inputDate = ed_wrkDtEnd.getValue();
    }

    let year = inputDate.substring(0, 4);
    let month = inputDate.substring(4, 6);
    // ed_pchsIntendDt.Text = year + month + cf_lastDate(year, f_del_zero(month)); // Need lastDate logic
    ed_pchsIntendDt.setValue(year + month+$c.date.getLastDateOfMonth(year + month));

    ed_rmk.setValue(""); // 비고
    ed_certiNo.setValue(""); // 거래명세서번호
    hid_rmk.setValue(""); // 비고
    ed_pstpnRsn.setValue(""); // 보류사유

    if (rowCnt == 0) {
        $c.gus.cfDisableAllBtn();
        $c.gus.cfDisableObjects([ed_pchsIntendDt, ed_pchsIntendDt, ed_rmk,ed_certiNo,btn_certiNo, hid_rmk, ed_pstpnRsn])
        // ed_pchsIntendDt.setDisabled(true);
        // img_pchsIntendDt.setDisabled(true);
        // txt_rmk.setDisabled(true);
        // ed_certiNo.setDisabled(true);
        // img_certiNo.setDisabled(true);
        // hid_rmk.setDisabled(true);
        // txt_pstpnRsn.setDisabled(true);
        await $c.win.alert(MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
    } else {
        $c.gus.cfEnableAllBtn();
        $c.gus.cfEnableObjects([ed_pchsIntendDt, ed_pchsIntendDt, ed_rmk, btn_certiNo, ed_pstpnRsn]);
        // ed_pchsIntendDt.setDisabled(false);
        // img_pchsIntendDt.setDisabled(false);
        // txt_rmk.setDisabled(false);
        // img_certiNo.setDisabled(false);
        // txt_pstpnRsn.setDisabled(false);
    }
    scwin.pchsSelAmt = 0;
    scwin.pchsSelCount = 0;
    scwin.pchsDcScSelAmt = 0;
    scwin.pchsSelVatAmt = 0;
    scwin.f_viewSelAmount();
};

