scwin.gr_containerTpchsAdmissionList_onheaderclick = function (headerId) {
    let i = 0;
    if (headerId == "h_chk") {

        let bcheck = gr_containerTpchsAdmissionList.getHeaderValue(headerId);
        if (bcheck == "T") {
            scwin.pchsSelAmt = 0;
            scwin.pchsSelCount = 0;
            scwin.pchsDcScSelAmt = 0;
            scwin.pchsSelVatAmt = 0;
            for (i = 0; i < ds_containerTpchsAdmissionList.getRowCount(); i++) {
                scwin.pchsSelAmt = scwin.pchsSelAmt + Number(ds_containerTpchsAdmissionList.getCellData(i, "basisTpchs"));
                scwin.pchsDcScSelAmt = scwin.pchsDcScSelAmt + Number(ds_containerTpchsAdmissionList.getCellData(i, "dcScAmt"));
                scwin.pchsSelVatAmt = scwin.pchsSelVatAmt + Number(ds_containerTpchsAdmissionList.getCellData(i, "vat"));
                scwin.pchsSelCount = scwin.pchsSelCount + 1;
            }
        } else {

            for (i = 0; i < ds_containerTpchsAdmissionList.getRowCount(); i++) {
                scwin.pchsSelAmt = scwin.pchsSelAmt - Number(ds_containerTpchsAdmissionList.getCellData(i, "basisTpchs"));
                scwin.pchsDcScSelAmt = scwin.pchsDcScSelAmt - Number(ds_containerTpchsAdmissionList.getCellData(i, "dcScAmt"));
                scwin.pchsSelVatAmt = scwin.pchsSelVatAmt - Number(ds_containerTpchsAdmissionList.getCellData(i, "vat"));
                scwin.pchsSelCount = scwin.pchsSelCount - 1;
            }
            scwin.pchsSelAmt = 0;
            scwin.pchsSelCount = 0;
            scwin.pchsDcScSelAmt = 0;
            scwin.pchsSelVatAmt = 0;
        }

        // 선택한 금액  표시
        scwin.f_viewSelAmount();
    }
};

scwin.gr_containerTpchsAdmissionList_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (columnId == "chk") {
        let check = ds_containerTpchsAdmissionList.getCellData(rowIndex, columnId);
        if (check == "T") {
            scwin.pchsSelAmt = scwin.pchsSelAmt + Number(ds_containerTpchsAdmissionList.getCellData(rowIndex, "basisTpchs"));
            scwin.pchsDcScSelAmt = scwin.pchsDcScSelAmt + Number(ds_containerTpchsAdmissionList.getCellData(rowIndex, "dcScAmt"));
            scwin.pchsSelVatAmt = scwin.pchsSelVatAmt + Number(ds_containerTpchsAdmissionList.getCellData(rowIndex, "vat"));
            scwin.pchsSelCount = scwin.pchsSelCount + 1;
        } else {
            scwin.pchsSelAmt = scwin.pchsSelAmt - Number(ds_containerTpchsAdmissionList.getCellData(rowIndex, "basisTpchs"));
            scwin.pchsDcScSelAmt = scwin.pchsDcScSelAmt - Number(ds_containerTpchsAdmissionList.getCellData(rowIndex, "dcScAmt"));
            scwin.pchsSelVatAmt = scwin.pchsSelVatAmt - Number(ds_containerTpchsAdmissionList.getCellData(rowIndex, "vat"));
            scwin.pchsSelCount = scwin.pchsSelCount - 1;
        }

        // 선택한 금액  표시
        scwin.f_viewSelAmount();
    }
};

scwin.gr_containerTpchsAdmissionList_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0) {
        if (columnId == "cntrNo" && ds_containerTpchsAdmissionList.getCellData(rowIndex, "cntrNo") != "") {
            scwin.f_CntrNoDetail(ds_containerTpchsAdmissionList.getCellData(rowIndex, "cntrNo"));
        }
    }
};

